string[] rawData = { "25.5", "30.2", "N/A", "28.0", "999" };
foreach (var raw in rawData)
{
    try
    {
        double val = double.Parse(raw);
        Print($"解析成功: {val}");
    }
    catch
    {
        Print($"数据异常，跳过: {raw}");
    }
}
Print("数据处理完毕");
